+    G[1] = -dimensions.y / 2.0;
+    G[2] = -dimensions.z / 2.0;
+    H[0] = dimensions.x / 2.0;
+    H[1] = -dimensions.y / 2.0;
+    H[2] = -dimensions.z / 2.0;
+
+    edge->addPoint(A);
+    edge->addPoint(B);
+    edge->finishLine();
+    edge->addPoint(B);
+    edge->addPoint(C);
+    edge->finishLine();
